package com.example.bankingapp;

import android.content.Context;
import android.os.Bundle;
import androidx.appcompat.app.AppCompatActivity;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;
import android.widget.Toast;

public class MainActivity extends AppCompatActivity {

    private EditText accountNumberEditText;
    private EditText amountEditText;
    private TextView balanceTextView;
    private Button transactionButton;
    private double currentBalance = 1000.0; // Simulated initial balance

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        accountNumberEditText = findViewById(R.id.account_number_edit_text);
        amountEditText = findViewById(R.id.amount_edit_text);
        balanceTextView = findViewById(R.id.balance_text_view);
        transactionButton = findViewById(R.id.transaction_button);

        updateBalanceDisplay();

        transactionButton.setOnClickListener(v -> {
            String accountNumber = accountNumberEditText.getText().toString();
            String amountStr = amountEditText.getText().toString();

            if (isValidTransaction(accountNumber, amountStr)) {
                double amount = Double.parseDouble(amountStr);
                currentBalance -= amount; // Simulate transaction
                updateBalanceDisplay();
                Toast.makeText(this, "Transaction successful!", Toast.LENGTH_SHORT).show();
            } else {
                Toast.makeText(this, "Invalid input!", Toast.LENGTH_SHORT).show();
            }
        });
    }

    private void updateBalanceDisplay() {
        balanceTextView.setText("Current Balance: $" + currentBalance);
    }

    private boolean isValidTransaction(String accountNumber, String amount) {
        // Simple validation
        return !accountNumber.isEmpty() && !amount.isEmpty() && Double.parseDouble(amount) > 0;
    }
}